class Common_Model_Cron extends Common_Model_Base_Cron {


    public function save(Doctrine_Connection $conn = null)
    {
        if (!$this->ID) {
            $this->DateCreated = date('y-m-d');
        }
        $this->setItems();
        parent::save($conn);
    }

    public function setItems(): void
    {
        $subItems = ['Minute' => 0, 'Hour' => 1, 'Day' => 2, 'Month' => 3, 'Week' => 4];
        if (trim($this->CronExpression)) {
            $subItemsSettings = preg_split('/\s+/', $this->CronExpression);
        } else {
            $subItemsSettings = array();
        }
        if (count($subItemsSettings) < 5) {
            $subItemsSettings = array_pad($subItemsSettings, 5, '*');
        }
        $modified = $this->getModified(true);
        $typeSet = key_exists('CronExpression', $modified);
        foreach ($subItems as $name => $index) {
            if (!trim($this->{$name})) {
                $this->{$name} = trim($subItemsSettings[$index]);
                continue;
            }
            if ($subItemsSettings[$index] != $this->{$name}) {
                if ($typeSet) {
                    $this->{$name} = trim($subItemsSettings[$index]);
                } else {
                    $subItemsSettings[$index] = trim($this->{$name});
                }
            }
        }
        $newValue = implode(' ', array_slice($subItemsSettings, 0, 5));
        if ($newValue <> $this->CronExpression) {
            $this->CronExpression = $newValue;
        }
        if (Cron\CronExpression::isValidExpression($this->CronExpression)) {
            $cron = new Cron\CronExpression($this->CronExpression);
            $this->NextRun = $cron->getNextRunDate()->format('Y-m-d H:i:00');
        } else {
            $this->Active = 0;
            $this->Note = 'Invalid settings ' . $this->Note;
        }
    }

    public static function getAction(): array
    {
        $now = date('Y-m-d H:i:00');
        $query = Doctrine_Query::create();
        $query->from('Common_Model_Cron cron');
        $query->addWhere('IFNULL(cron.Active, 0) <> 0');
        $query->addWhere('cron.CronExpression IS NOT NULL');
        $query->addWhere('cron.Script IS NOT NULL');
        $query->addWhere('(cron.NextRun <= "' . $now . '" OR cron.NextRun IS NULL)');
        $query->addSelect('cron.CronExpression, cron.Script, IF(cron.NextRun IS NULL, false, cron.NextRun <= "' . $now . '") AS IsPast');
        $crons = $query->execute();

        $actions = array();
        /** @var Common_Model_Cron $cron */
        foreach ($crons as $cronItem) {
            $cron = new Cron\CronExpression($cronItem->CronExpression);
            $cronItem->NextRun = $cron->getNextRunDate()->format('Y-m-d H:i:00');
            $cronItem->save();
            if ($cron->isDue() || $cronItem->IsPast) {
                $actions[] = $cronItem;
            }
        }

        return $actions;
    }

    /**
     * @param int $cron_ID
     * @return Common_Model_Cron|false
     */
    public static function getCron(int $cron_ID): self|false
    {
        $query = Doctrine_Query::create();
        $query->from('Common_Model_Cron cron');
        $query->addWhere('cron.ID = ?', $cron_ID);

        return $query->fetchOne();
    }

    /**
     * Vrátí název cronu, případně action
     * @return string|null
     */
    public function getName(): ?string
    {
        return $this->Name ?? $this->Script ?? null;
    }


}